import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { HouseholdService } from '../../../services/household.service';
import { Household } from '../../../models/models';

@Component({
  selector: 'app-household-form',
  templateUrl: './household-form.component.html',
  styleUrls: ['./household-form.component.css']
})


export class HouseholdFormComponent implements OnInit {
  @Input() household: Household | null = null;
  @Output() saved = new EventEmitter<Household>();
  @Output() cancelled = new EventEmitter<void>();

  form: FormGroup;
  loading = false;
  error = '';

  constructor(private fb: FormBuilder, private householdService: HouseholdService) {
    this.form = this.fb.group({
      name: ['', Validators.required],
      description: ['']
    });
  }

  ngOnInit(): void {
    if (this.household) {
      this.form.patchValue(this.household);
    }
  }

  submit(): void {
    if (this.form.invalid) return;
    this.loading = true;
    this.error = '';
    const data = this.form.value;
    const obs = this.household
      ? this.householdService.update(this.household.id, data)
      : this.householdService.create(data);

    obs.subscribe({
      next: (h) => { this.loading = false; this.saved.emit(h); },
      error: (err) => {
        this.error = err.error?.name?.[0] || 'Failed to save household.';
        this.loading = false;
      }
    });
  }
}
<div class="modal-overlay" (click)="cancelled.emit()">
  <div class="modal" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <h2>{{ household ? 'Edit' : 'New' }} Household</h2>
      <button class="modal-close" (click)="cancelled.emit()">x</button>
    </div>

    <div class="alert alert-danger" *ngIf="error">{{ error }}</div>

    <form [formGroup]="form" (ngSubmit)="submit()">
      <div class="form-group">
        <label>Name *</label>
        <input class="form-control" formControlName="name" placeholder="e.g. My Home"
          [class.is-invalid]="form.get('name')?.invalid && form.get('name')?.touched">
        <div class="error-msg" *ngIf="form.get('name')?.errors?.['required'] && form.get('name')?.touched">
          Name is required
        </div>
      </div>
      <div class="form-group">
        <label>Description</label>
        <textarea class="form-control" formControlName="description"
          placeholder="Optional description" rows="3"></textarea>
      </div>
      <div class="modal-footer">
        <button type="button" class="btn btn-secondary" (click)="cancelled.emit()">Cancel</button>
        <button type="submit" class="btn btn-primary" [disabled]="form.invalid || loading">
          {{ loading ? 'Saving...' : (household ? 'Update' : 'Create') }}
        </button>
      </div>
    </form>
  </div>
</div>
